24	function countNeighbors(cells: Cell[]): Map<string, { cell: Cell; count: number }> {
25	  const counts = new Map<string, { cell: Cell; count: number }>();
26	  for (const [x, y] of cells) {
27	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
28	      const neighbor: Cell = [x + dx, y + dy];
29	      const key = cellKey(neighbor);
30	      const existing = counts.get(key);
31	      counts.set(key, {
32	        cell: neighbor,
33	        count: (existing?.count ?? 0) + 1,
34	      });
35	    }
36	  }
37	  return counts;
38	}
39	
40	function cellLivesNextGeneration(isAlive: boolean, neighborCount: number): boolean {
41	  return neighborCount === 3 || (isAlive && neighborCount === 2);
42	}
